async function step11_triggers(c) {
  console.log("\n── updated_at Triggers ─────────────────────────────────");

  await tryExec(c, "FUNCTION update_updated_at", `
    CREATE OR REPLACE FUNCTION update_updated_at()
    RETURNS TRIGGER AS $$
    BEGIN
      NEW.updated_at = NOW();
      RETURN NEW;
    END;
    $$ LANGUAGE plpgsql
  `);

  const triggerTables = [
    "users", "wallets", "user_credits", "orders", "studio_branding",
    "payment_gateway_configs", "gst_configurations", "invoices",
    "refund_requests", "wallet_adjustments", "youtube_channels", "packages",
  ];

  for (const t of triggerTables) {
    const tname = `trg_${t}_updated_at`;
    await tryExec(c, `TRIGGER ${tname}`, `
      DO $$
      BEGIN
        IF NOT EXISTS (
          SELECT 1 FROM pg_trigger WHERE tgname = '${tname}'
        ) THEN
          CREATE TRIGGER ${tname}
          BEFORE UPDATE ON ${t}
          FOR EACH ROW EXECUTE FUNCTION update_updated_at();
        END IF;
      END $$
    `);
  }
}

