async function main() {
  console.log("=============================================================");
  console.log("  StreamLivee — Complete DB Migration");
  console.log("  Target:", DATABASE_URL.replace(/:([^:@]+)@/, ":***@"));
  console.log("=============================================================");

  const client = new Client({ connectionString: DATABASE_URL });
  await client.connect();
  console.log("✓  Connected to PostgreSQL");

  try {
    await step1_extensions(client);
    await step2_enums(client);
    await step3_core_tables(client);
    await step4_events_orders(client);
    await step5_payments(client);
    await step6_branding_domains(client);
    await step7_notifications(client);
    await step8_refunds_adjustments(client);
    await step9_gst_invoices(client);
    await step10_youtube_templates(client);
    await step11_triggers(client);
    await step12_seed_admin(client);
    await step13_seed_settings(client);
    await step14_seed_templates(client);

    // Final verification
    console.log("\n── Verification ────────────────────────────────────────");
    const tables = await client.query(
      `SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' ORDER BY table_name`
    );
    console.log(`\n  Total tables: ${tables.rows.length}`);
    console.log("  Tables:", tables.rows.map((r) => r.table_name).join(", "));

    const adminRow = await client.query(`SELECT id, email, role FROM users WHERE role = 'admin'`);
    console.log(`\n  Admin users: ${adminRow.rows.length}`);
    if (adminRow.rows.length > 0) {
      console.log("  →", adminRow.rows[0].email);
    }

    const settingsCount = await client.query(`SELECT COUNT(*) AS c FROM platform_settings`);
    console.log(`\n  Platform settings: ${settingsCount.rows[0].c}`);

    const templateCount = await client.query(`SELECT COUNT(*) AS c FROM event_templates`);
    console.log(`  Event templates  : ${templateCount.rows[0].c}`);

    console.log("\n=============================================================");
    console.log("  ✅  MIGRATION COMPLETE");
    console.log("  Create admin: node scripts/seed-production-admin.js");
    console.log("=============================================================\n");
  } catch (e) {
    console.error("\n❌ Fatal error:", e.message);
    throw e;
  } finally {
    await client.end();
  }
}

main().catch((e) => {
  console.error("Fatal:", e);
  process.exit(1);
});
